insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('88899', 'u.dang', 'udang', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"krustasea yang memiliki panjang mencapai 25 cm untuk beberapa jenis (biasanya 2 cm), memiliki antena panjang, kaki ramping, dan perut berotot pipih, hidup di segala habitat, tersebar di seluruh dunia〔Caridea〕","contoh":[]}]', null, '["perudangan"]', '["udang bago","udang batu","udang belang","udang beras","udang bulu","udang buta","udang dogol","udang galah","udang gantung","udang geragau","udang jerbung","udang karang","udang kecepai","udang kering","udang ketak","udang krosok","udang lubuk","udang macan","udang mantis merak","udang menjangan","udang pasir","udang peci","udang pepai","udang pistol","udang putih","udang rarak","udang rebon","udang regang","udang satang","udang selingkuh","udang sungai","udang tawar","udang vaname","udang windu"]', '["ada udang (berudang) di balik batu","ada udang di balik batu","asing udang, asing nikmat","asing udang, lain nikmat","hitam, hitam gagak, putih, putih udang kapai (hitam, hitam bendi, putih, putih sadah)","hitam-hitam gajah, putih-putih udang kepai","semisal udang dalam tangguk","seperti kepiting tidak tahu bungkuknya (sebagai udang tak tahu bungkuknya)","udang dalam tangguk","udang hendak mengatai ikan","udang tak tahu bungkuknya","udang tak tahu di bungkuknya"]', '["seperti udang dipanggang"]', '[{"peribahasa":"ada udang (berudang) di balik batu","makna":"Terdapat maksud atau tujuan tersembunyi di balik suatu perbuatan, perkataan, atau sikap yang ditunjukkan."},{"peribahasa":"ada udang di balik batu","makna":"Terdapat maksud atau tujuan tersembunyi di balik suatu perbuatan, perkataan, atau sikap yang ditunjukkan."},{"peribahasa":"asing udang, asing nikmat","makna":"Setiap bangsa, suku, atau daerah memiliki adat istiadat, kebiasaan, dan kesenangan yang berbeda-beda."},{"peribahasa":"asing udang, lain nikmat","makna":"Setiap bangsa, suku, atau daerah memiliki adat istiadat, kebiasaan, dan kesenangan yang berbeda-beda."},{"peribahasa":"hitam, hitam gagak, putih, putih udang kapai (hitam, hitam bendi, putih, putih sadah)","makna":"Hendaklah berhati-hati terhadap perkataan yang manis karena mungkin saja mengandung tipu muslihat atau niat buruk."},{"peribahasa":"hitam-hitam gajah, putih-putih udang kepai","makna":"Jangan menilai sesuatu hanya dari penampilan luarnya saja, karena yang tampak buruk belum tentu buruk dan yang tampak baik belum tentu baik."},{"peribahasa":"semisal udang dalam tangguk","makna":"Berada dalam keadaan yang sangat sulit, terjepit, dan tidak berdaya untuk melepaskan diri."},{"peribahasa":"seperti kepiting tidak tahu bungkuknya (sebagai udang tak tahu bungkuknya)","makna":"Tidak menyadari kekurangan, kesalahan, atau aib yang ada pada diri sendiri."},{"peribahasa":"udang dalam tangguk","makna":"Berada dalam keadaan yang sangat sulit, terjepit, dan tidak berdaya untuk melepaskan diri."},{"peribahasa":"udang hendak mengatai ikan","makna":"Orang yang mencela atau mengkritik orang lain tanpa menyadari bahwa dirinya sendiri memiliki kekurangan atau kesalahan yang sama, bahkan mungkin lebih buruk."},{"peribahasa":"udang tak tahu bungkuknya","makna":"Tidak menyadari kekurangan, kesalahan, atau aib yang ada pada diri sendiri."},{"peribahasa":"udang tak tahu di bungkuknya","makna":"Tidak menyadari kekurangan, kesalahan, atau aib yang ada pada diri sendiri."}]');
