insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('89090', 'u.jung', 'ujung', '', '', '["Nomina","Nomina","Nomina","Nomina","Nomina","kiasan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian penghabisan dari suatu benda (yang panjang)","contoh":[{"nomor":2,"teks":"serangga itu merusakkan -- akar anggrek"},{"nomor":4,"teks":"berbelok di -- jalan"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian barang yang diruncingkan (lancip, tajam, dan sebagainya); puncak","contoh":[{"nomor":2,"teks":"-- hidung"},{"nomor":4,"teks":"-- jari"},{"nomor":6,"teks":"-- tombak"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian darat yang menjorok (jauh) ke laut","contoh":[]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"(bagian) akhir (pembicaraan, percakapan, tahun, dan sebagainya)","contoh":[{"nomor":2,"teks":"-- pembicaraan baginda masih terhadap hal itu jua"},{"nomor":4,"teks":"gajinya tidak cukup sampai ke -- bulan"}]},{"nomor":"5","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"ki","nama":"kiasan","tipe":"kelas_kata"}],"definisi":"maksud dan tujuan (perkataan dan sebagainya)","contoh":[{"nomor":2,"teks":"saya maklum akan -- perkataannya itu"}]}]', null, '["berujung","mengujung","pengujung","seujung","ujung-ujungnya"]', '["ujung akar","ujung atap","ujung bumi","ujung garis akhir","ujung hidung","ujung jari","ujung jarum","ujung kuku","ujung lidah","ujung mata","ujung panah","ujung pangkal","ujung pengabdian","ujung perkataan","ujung tanduk","ujung tombak"]', '["bergantung di ujung kuku","berniaga di ujung lidah","embun di ujung rumput","hidup di ujung gurung orang","jiwa bergantung di ujung rambut","kapur di ujung tanduk","kita di pangkal merawal dia di ujung merawal","kusut di ujung tali, tiliklah di pangkalnya","kusut ujung dengan pangkalnya","lalu (lulus) ujung, lalu (lulus) kelindan","merantau di sudut dapur, merantau ke ujung bendul","nyawa bergantung di ujung kuku","sesat di ujung jalan, balik ke pangkal jalan","sesat di ujung jalan, surut ke pangkal jalan","seperti embun di ujung rumput","seperti gunting makan di ujung","telur di ujung tanduk","ujung jarum halus kelindan sutra"]', '["di ujung lidah","mengadu ujung jarum","mengadu ujung penjahit","ujung jari sambungan lidah"]', '[{"peribahasa":"bergantung di ujung kuku","makna":"Berada dalam keadaan yang sangat berbahaya, kritis, atau genting."},{"peribahasa":"berniaga di ujung lidah","makna":"Orang yang pandai berdagang atau mencari keuntungan dengan menggunakan kata-kata manis, bujukan, atau tipu muslihat."},{"peribahasa":"embun di ujung rumput","makna":"Sesuatu yang bersifat tidak kekal, mudah hilang, atau cepat berubah."},{"peribahasa":"hidup di ujung gurung orang","makna":"Hidup dalam kemiskinan dan sepenuhnya bergantung pada belas kasihan atau bantuan orang lain."},{"peribahasa":"jiwa bergantung di ujung rambut","makna":"Berada dalam keadaan yang sangat berbahaya dan mengancam keselamatan jiwa."},{"peribahasa":"kapur di ujung tanduk","makna":"Keadaan yang sangat sulit, genting, dan berada di ambang kegagalan atau kehancuran."},{"peribahasa":"kita di pangkal merawal dia di ujung merawal","makna":"Dua pihak yang memiliki pendirian yang saling bertentangan dan tidak mungkin dapat didamaikan."},{"peribahasa":"kusut di ujung tali, tiliklah di pangkalnya","makna":"Jika terjadi suatu permasalahan atau perselisihan, hendaknya dicari akar permasalahannya sejak awal."},{"peribahasa":"kusut ujung dengan pangkalnya","makna":"Suatu permasalahan yang sudah terlanjur sangat rumit dan sulit untuk diuraikan atau diselesaikan."},{"peribahasa":"lalu (lulus) ujung, lalu (lulus) kelindan","makna":"Jika seorang pemimpin atau atasan telah berhasil melewati suatu rintangan, maka bawahan atau pengikutnya pun akan ikut berhasil."},{"peribahasa":"merantau di sudut dapur, merantau ke ujung bendul","makna":"Pergi merantau ke tempat yang tidak jauh dari kampung halaman atau tempat tinggalnya."},{"peribahasa":"nyawa bergantung di ujung kuku","makna":"Berada dalam keadaan yang sangat berbahaya, kritis, atau genting."},{"peribahasa":"sesat di ujung jalan, balik ke pangkal jalan","makna":"Apabila menyadari telah melakukan kesalahan, hendaknya segera kembali ke jalan yang benar atau memperbaiki kesalahan tersebut."},{"peribahasa":"sesat di ujung jalan, surut ke pangkal jalan","makna":"Apabila menyadari telah melakukan kesalahan, hendaknya segera kembali ke jalan yang benar atau memperbaiki kesalahan tersebut."},{"peribahasa":"seperti embun di ujung rumput","makna":"Sesuatu yang bersifat tidak kekal, mudah hilang, atau cepat berubah."},{"peribahasa":"seperti gunting makan di ujung","makna":"Orang yang secara diam-diam namun sangat tajam dan efektif dalam perkataan, tindakan, atau kritiknya."},{"peribahasa":"telur di ujung tanduk","makna":"Keadaan yang sangat berbahaya, genting, dan berada di ambang kegagalan atau kehancuran."},{"peribahasa":"ujung jarum halus kelindan sutra","makna":"Tipu muslihat atau siasat yang sangat halus, licik, dan sulit untuk diketahui."}]');
