insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('89861', 'un.tung', 'untung', '', '', '["Nomina","Adjektiva","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"sesuatu (keadaan) yang telah digariskan oleh Tuhan Yang Maha Kuasa bagi perjalanan hidup seseorang; nasib","contoh":[{"nomor":2,"teks":"kalau ada -- di badan bolehlah kita bertemu lagi"}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"mujur; bahagia","contoh":[{"nomor":2,"teks":"--lah saat-saat demikian mereka dapat menyelamatkan diri"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"laba yang diperoleh dalam berdagang dan sebagainya","contoh":[{"nomor":2,"teks":"kita bukan pedagang yang dapat membeli sayur di desa dan menjualnya dengan -- besar di kota"}]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"guna; manfaat; faedah","contoh":[{"nomor":2,"teks":"apa --nya menakut-nakuti orang"}]}]', null, '["beruntung","beruntung-untung","keberuntungan","keuntungan","menguntungkan","peruntung","peruntungan","seberuntung-beruntungnya","untung-untung","untung-untungan"]', '["untung batu","untung malang","untung sabut","untung sero"]', '["biarpun setandan bagai kelapa, tetapi untung berlain-lainan","ikhtiar menjalani untung menyudahi","untung ada, tuah tiada","untung bagai untung kapas","untung melambung, malang menimpa","untung sabut timbul, untung batu tenggelam"]', '["tidak tahu di untung"]', '[{"peribahasa":"biarpun setandan bagai kelapa, tetapi untung berlain-lainan","makna":"Meskipun berasal dari keluarga atau lingkungan yang sama, nasib dan jalan hidup setiap orang dapat berbeda-beda."},{"peribahasa":"ikhtiar menjalani untung menyudahi","makna":"Manusia memiliki kewajiban untuk berusaha dan berikhtiar sekuat tenaga, namun hasil akhirnya tetap berada di tangan Tuhan."},{"peribahasa":"untung ada, tuah tiada","makna":"Meskipun mendapatkan keuntungan atau hasil yang baik, hal tersebut tidak mendatangkan kebahagiaan, kemuliaan, atau manfaat yang berarti."},{"peribahasa":"untung bagai untung kapas","makna":"Memiliki nasib yang sangat baik dan selalu beruntung dalam segala hal."},{"peribahasa":"untung melambung, malang menimpa","makna":"Mengharapkan untuk mendapatkan keuntungan atau keberhasilan yang besar, namun yang terjadi justru sebaliknya, yaitu kerugian atau kemalangan."},{"peribahasa":"untung sabut timbul, untung batu tenggelam","makna":"Dalam setiap usaha atau perjuangan, nasib setiap orang berbeda-beda; ada yang berhasil dan selamat, ada pula yang gagal dan celaka."}]');
